from flask import Flask, request
from flask_pymongo import PyMongo
from bson.json_util import dumps
from bson.objectid import ObjectId

app = Flask(__name__)

# configure MongoDB connection
app.config['MONGO_URI'] = 'mongodb://localhost:27017/myDatabase'
mongo = PyMongo(app)

@app.route('/addUser', methods=['POST'])
def add_user():
    _json = request.json
    userId = mongo.db.users.insert({"name": _json["name"], "email": _json["email"]})
    if userId:
        return dumps({'status': 'success', 'message': 'User inserted successfully!'}), 201
    else:
        return dumps({'status': 'failed', 'message': 'Failed to insert User.'}), 400

@app.route('/updateUser/<id>', methods=['PUT'])
def update_user(id):
    _json = request.json
    user = mongo.db.users.update({'_id': ObjectId(id)}, {"name": _json["name"], "email": _json["email"]})
    if user:
        return dumps({'status': 'success', 'message': 'User updated successfully!'}), 201
    else:
        return dumps({'status': 'failed', 'message': 'Failed to update User.'}), 400

@app.route('/getUsers', methods=['GET'])
def get_users():
    users = mongo.db.users.find()
    resp = dumps(users)
    return resp, 200

if __name__ == "__main__":
    app.run(port=5000, debug=True)